#include<bits/stdc++.h>
using namespace std;
char s[200010],s1[200010];
int p[2000010],ans,cnt;
int main()
{
    while(scanf("%s",s1+1)!=EOF)
    {
        s[0]='~';
        s[cnt=1]='|';
        int n=strlen(s1+1);
        for(int i=1;i<=n;i++)
        {
            s[++cnt]=s1[i];
            s[++cnt]='|';
        }
        int r=0,mid=0;
        for(int i=1;i<=cnt;i++)
        {
            p[i]=0;
            if(i<=r)
            {
                p[i]=min(p[mid*2-i],r-i+1);
            }
            while(s[i-p[i]]==s[i+p[i]])
            {
                p[i]++;
            }
            if(p[i]+i>r)
            {
                r=p[i]+i-1;
                mid=i;
            }
            if(p[i]+i-1==cnt)
            {
                ans=p[i]-1;
                break;
            }
        }
        printf("%s",s1+1);
        for(int i=n-ans;i>=1;i--)
        {
            printf("%c",s1[i]);
        }
        printf("\n");
    }
    return 0;
}
